sys_ws_operation.operation_script:
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) { 
    var sysId = request.pathParams.sys_id;

    var gr = new GlideRecord('x_1667915_4dot_social_media_activity');
    if (!gr.get(sysId)) {
        response.setStatus(404);
        return { error: "Post not found." };
    }

    if (gr.status != 'Approved') {
        response.setStatus(400);
        return { error: "Post is not approved. Cannot publish." };
    }

    var now = new GlideDateTime();
    var scheduled = new GlideDateTime(gr.scheduled_date_time);
    if (scheduled.after(now)) {
        response.setStatus(400);
        return { error: "Scheduled time has not yet arrived: " + scheduled.getDisplayValue() };
    }

    gr.status = 'Published';
    gr.update();

    var attachments = [];
    var attachmentGR = new GlideRecord('sys_attachment');
    attachmentGR.addQuery('table_name', 'x_1667915_4dot_social_media_activity');
    attachmentGR.addQuery('table_sys_id', sysId);
    attachmentGR.query();

    var instanceUrl = gs.getProperty("glide.servlet.uri");

    while (attachmentGR.next()) {
        attachments.push({
            sys_id: attachmentGR.getUniqueValue(),
            file_name: attachmentGR.getValue('file_name'),
            download_url: instanceUrl + "api/now/attachment/" + attachmentGR.getUniqueValue() + "/file"
        });
    }

    var attachmentMessage = (attachments.length > 0)
        ? attachments.length + " attachment(s) found and linked to this post."
        : "No attachments found for this post.";

    return {
        message: "✅ Post '" + gr.content_description + "' (ID: " + gr.getUniqueValue() + ") published successfully.",
        post: {
            sys_id: gr.getUniqueValue(),
            platform: gr.platform.toString(),
            scheduled_time: gr.scheduled_date_time.getDisplayValue(),
            description: gr.content_description.toString(),
            status: gr.status.toString(),
            attachments: {
                message: attachmentMessage,
                files: attachments
            }
        }
    };

})(request, response);
